def create_booking(date_iso):
    url = f"{BASE_URL}/api/bookings"
    payload = {
        "date": date_iso,
        "user": {
            "name": "Test User",
            "email": "testuser@example.com"
        },
        "slot": "10:00-11:00"
    }    
    response = requests.post(url, json=payload, headers=HEADERS, timeout=30)
    return response

def test_create_booking_restricted_to_sundays_and_mondays():
    # Days 0=Monday ... 6=Sunday
    # Find a Tuesday (2), Wednesday(3), Thursday(4), Friday(5), Saturday(6)
    # Sunday=6, Monday=0

    # We'll test booking for each day of the next week and verify allowed only for Sunday and Monday.
    # Sunday and Monday should succeed (201)
    # Other days should fail with 4xx
    base_date = datetime.utcnow()
    results = {}
    booked_ids = []

    try:
        for i in range(7):
            check_date = base_date + timedelta(days=i)
            weekday = check_date.weekday()  # Monday=0 ... Sunday=6
            date_iso = check_date.strftime("%Y-%m-%d")

            response = create_booking(date_iso)
            results[date_iso] = {
                "status_code": response.status_code,
                "response_body": response.json() if response.headers.get("Content-Type","").startswith("application/json") else response.text
            }

            # If booking succeeded, store ID for cleanup if provided
            if response.status_code == 201:
                try:
                    booking_id = response.json().get("id")
                    if booking_id:
                        booked_ids.append(booking_id)
                except Exception:
                    pass
    finally:
        # Cleanup created bookings if any
        for bid in booked_ids:
            try:
                del_resp = requests.delete(f"{BASE_URL}/api/bookings/{bid}", headers=HEADERS, timeout=30)
                # no assertion here for cleanup
            except Exception:
                pass

    # Assert bookings success only on Sunday (6) and Monday(0)
    for i in range(7):
        test_date = (base_date + timedelta(days=i)).strftime("%Y-%m-%d")
        status = results[test_date]["status_code"]

        weekday = (base_date + timedelta(days=i)).weekday()
        if weekday in [0, 6]:  # Monday=0, Sunday=6
            assert status == 201, f"Expected booking to succeed on {test_date} (weekday {weekday}), got status {status}."
        else:
            # Should be rejected (ideally client error 400 or 403)
            assert status != 201 and 400 <= status < 500, f"Expected booking to be rejected on {test_date} (weekday {weekday}), got status {status}."

